#include "knowledgebank.h"

const QVector<KnowledgeEntry>& KnowledgeBank::entries() {
    static const QVector<KnowledgeEntry> s_entries = {
        {"C++11特性 — 统一的初始化方法", "可以统一用{}初始化\n\n``` cpp\n#include <iostream>\n#include <vector>\n#include <map>\n#include <string>\nusing namespace std;\n\nint main() {\n    // ==================== 基本类型 ====================\n    int a = 10;           // 传统写法\n    int b{10};            // 统一初始化（推荐）\n\n    double x{3.14};\n    char ch{'A'};\n    bool flag{true};\n\n    // ==================== 数组 ====================\n    int arr1[5] = {1, 2, 3, 4, 5};   // 传统\n    int arr2[]{1, 2, 3, 4, 5};       // 统一初始化（推荐）\n\n    // ==================== STL 容器 ====================\n    vector<int> v1 = {10, 20, 30, 40, 50};     // 非常方便\n    vector<int> v2{10, 20, 30, 40, 50};        // 省略=也可以\n\n    set<string> s{\"apple\", \"banana\", \"orange\"};\n\n    map<string, int> m{\n        {\"tom\", 85},\n        {\"jack\", 92},\n        {\"mary\", 78}\n    };\n\n    cout << \"统一初始化示例完成！\" << endl;\n    return 0;\n}\n```"},
        {"C++11特性 — 成员变量默认初始值", "``` cpp\n#include <iostream>\n#include <string>\nusing namespace std;\n\nclass Student {\npublic:\n    string name = \"未命名\";     // 成员变量默认初始值\n    int age = 18;               // 默认值为18\n    double score{85.5};         // 统一初始化写法（推荐）\n    bool isMale = true;\n\n    void print() {\n        cout << \"姓名: \" << name \n             << \" 年龄: \" << age \n             << \" 分数: \" << score << endl;\n    }\n};\n\nint main() {\n    Student s1;                    // 使用所有默认值\n    s1.print();                    // 输出: 姓名: 未命名 年龄: 18 分数: 85.5\n\n    Student s2{\"张三\", 20, 92.5};  // 如果提供构造函数则覆盖默认值\n    s2.print();\n\n    return 0;\n}\n```"},
        {"C++11特性 — 智能指针", "| 类型       | 特点         |\n|------------|--------------|\n| unique_ptr | 独占所有权   |\n| shared_ptr | 共享所有权   |\n| weak_ptr   | 解决循环引用 |\n\n``` cpp\n#include <memory>\n```\n\n``` cpp\n#include <memory>\n#include <iostream>\nusing namespace std;\n\nint main() {\n    unique_ptr<int> p = make_unique<int>(10);\n\n    cout << *p << endl;\n}\n```\n\n``` cpp\nunique_ptr<int> p1 = make_unique<int>(10);\nunique_ptr<int> p2 = move(p1);\n```"},
        {"C++11特性 — 右值引用与移动构造函数<img", "src=\"C%2B%2B11%E7%89%B9%E6%80%A7-media/760beb584d8cd3cdec61ccbd82ae6959516e4fac.png\"\nclass=\"wikilink\" alt=\"Pastedimage20260425165510.png\" />\n\n右值：\n- 临时对象\n- 不能取地址\n- 即将被销毁\n\n``` cpp\nint b = 10;       // 10 是右值\nint c = a + b;    // a+b 是右值\n```\n\n右值引用：\n语法：\n\n``` cpp\nT&&\n```\n\n示例：\n\n``` cpp\nint&& x = 10;\n```\n\n移动构造函数\n语法：\n\n``` cpp\n类名(类名&& other)\n```\n\n它接收：右值引用\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass MyArray {\nprivate:\n    int* data;\n    int size;\n\npublic:\n    // 构造\n    MyArray(int s) : size(s) {\n        data = new int[size];\n        cout << \"构造函数\\n\";\n    }\n\n    // 拷贝构造\n    MyArray(const MyArray& other) : size(other.size) {\n        data = new int[size];\n        for(int i = 0; i < size; i++)\n            data[i] = other.data[i];\n        cout << \"拷贝构造\\n\";\n    }\n\n    // ✅ 移动构造\n    MyArray(MyArray&& other) : data(other.data), size(other.size) {\n        other.data = nullptr;\n        other.size = 0;\n        cout << \"移动构造\\n\";\n    }\n\n    ~MyArray() {\n        delete[] data;\n    }\n};\n```\n\nmove 函数\n\n``` cpp\nstd::move(x)\n```\n\n并不会移动东西，它只是：把 x 强制转换成**右值**让**移动构造函数**被调用。\n\n自动调用移动构造函数：\n1. 返回局部对象\n2. 插入容器\n\n移动赋值运算符\n\n``` cpp\nMyArray& operator=(MyArray&& other) {\n    if (this != &other) {\n        delete[] data;          // 释放旧资源\n\n        data = other.data;      // 接管资源\n        other.data = nullptr;   // 置空\n\n    }\n    return *this;\n}\n```"},
        {"C++11特性 — lambda表达式", "\\`\\`\\`\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nint main() {\n    auto add = [](int a, int b) { return a + b; };\n    \n    cout << add(3, 5) << endl;        // 输出 8\n    cout << add(10, 20) << endl;      // 输出 30\n}\n```\n\n``` cpp\nint main() {\n    int a = 10, b = 20;\n\n    auto func1 = [=]() { cout << a + b << endl; };     // 值捕获\n    auto func2 = [&]() { a = 100; };                    // 引用捕获，可修改外部变量\n\n    func1();\n    func2();\n    cout << a << endl;   // 输出 100\n}\n```\n\nmutable关键字\n\n``` cpp\nauto f = [x]() mutable {\n    x++;   // ✅ 允许修改副本，修改的只是副本，不影响外部变量\n};\n```"},
        {"STL库 — 基本概念：", "1.  容器：可容纳各种数据类型的数据结构\n2.  迭代器：可依次存取容器中元素的工具\n3.  算法：用来操作容器中元素的函数模板"},
        {"STL库 — 容器", "### 分类\n\n1.  顺序容器/序列容器 vector，deque，list\n2.  关联容器/有序容器 set,multiset,map,multimap\n3.  容器适配器 stack,queue,priority_queue\n\n注：1/2统称为第一类容器\n\\>第一类容器特有的函数\n- begin\n- end\n- rbegin\n- rend\n- erase\n- clear\n\n插入容器：\n1. 插入的是**复制品**\n2. 应该实现`==`和\\<运算符\n\n### 顺序容器\n\n1.  vector 动态数组，尾端增删\n2.  deque 动态数组，两端增删\n3.  list 双向链表，不支持随机存取，任何位置增删\n\n共同操作：\n- front() 第一个元素的**引用**\n- back() 最后一个元素的**引用**\n- push_back() 末尾增加新元素\n- pop_back() 删除容器末尾的元素\n\\#### list容器\n\n``` cpp\n#include <iostream>\n#include <list>\n#include <algorithm>\nusing namespace std;\n\nint main() {\n    list<int> lst{1, 2, 3, 4, 5};\n\n    lst.push_front(0);           // 头部插入\n    lst.push_back(6);            // 尾部插入\n\n    // 在值为3的位置前面插入 99\n    auto it = find(lst.begin(), lst.end(), 3);\n    if (it != lst.end()) {\n        lst.insert(it, 99);\n    }\n\n    lst.remove(4);               // 删除所有值为4的元素（list特有，高效）\n\n    for (int x : lst) {\n        cout << x << \" \";        \n    }\n}\n```"},
        {"STL库 — 容器", "- **`push_front()` / `pop_front()`**：头部操作\n- **`erase()`**：删除指定位置，**只有当前迭代器失效**，其他迭代器仍然有效\n- **`remove(val)`**：删除所有等于 `val` 的元素\n- **`remove_if(pred)`**：按条件删除\n- **`splice()`**：把另一个 list 的节点**转移**过来\n- **`merge()`**：合并两个**已排序**的 list\n- **`sort()`**：list 自己的排序算法（不能用 `std::sort`，因为 list 不支持随机迭代器）\n- **`unique()`**：删除**连续**的重复元素\n- **`reverse()`**：反转链表\n\n### 关联容器"},
        {"STL库 — 容器", "1.  set/multiset\n    集合 set不允许相同元素，multiset允许\n2.  map/multimap\n    映射 存放成对的key/value，根据key排序\n    map不允许相同key的元素，multimap允许\n\n共有操作：\n- **`find(key)`**：查找某个值，返回迭代器（找不到返回 `end()`）\n- **`lower_bound(key)`**：返回**第一个不小于** `key` 的元素的迭代器（≥ key）\n- **`upper_bound(key)`**：返回**第一个大于** `key` 的元素的迭代器（\\> key）\n- **`equal_range(key)`**：同时返回 `lower_bound` 和 `upper_bound`，返回一个 `pair`\n- **`count(key)`**：统计等于 `key` 的元素个数（`set`/`map` 只能是 0 或 1）\n- **`insert()`**：插入元素\n\n``` cpp\n#include <iostream>\n#include <set>\nusing namespace std;\n\nint main() {\n    set<int> s = {10, 20, 30, 30, 40};   // 30只会插入一次\n    \n    auto it = s.find(30);\n    if (it != s.end()) {\n        cout << \"找到: \" << *it << endl;\n    }\n    \n    auto lb = s.lower_bound(25);   // 指向 30\n    auto ub = s.upper_bound(30);   // 指向 40\n    \n    cout << \"lower_bound(25) -> \" << *lb << endl;\n    cout << \"upper_bound(30) -> \" << *ub << endl;\n    \n    return 0;\n}\n```"},
        {"STL库 — 容器", "### 容器适配器\n\n1.  stack 栈 后进先出\n2.  queue 队列 先进先出\n3.  priority_queue 优先级队列，优先级最高的总是第一个出列"},
        {"STL库 — 迭代器", "指向**第一类容器**中的元素\n定义\n`容器类名::iterator 变量名`或\n`容器类名::const iterator 变量名`\n访问指向的元素：`* 迭代器变量名`\n指向下一个元素：++\npast-the-end值：容器中最后一个元素的后面，用来访问对象是非法的"},
        {"STL库 — 分类------由弱到强", "所有：`p++,++p`\n1. 输入 只读 `*p,p=p1,p==p1,p!=p1`\n2. 输出 只写 `*p,p=p1`\n3. 正向 读写 `以上全部`\n4. 双向 读写+向前向后 `以上全部，p--,--p` `list/set/multiset/map/multimap`\n5. 随机访问 读写+随机移动 \\`以上全部,以及p+=i,p-=i,p+i,p-i;p\\<p1,p\\<=p1,p\\>p1,p\\>=p1,p\\[i\\] vector/deque"},
        {"STL库 — 算法", "通过**迭代器**来操纵**容器**中的元素的**函数模板**\n\\### 分类\n- 不变序列 不会修改所作用的容器或对象\n- 变值 会修改原区间或目标区间，**不可以属于关联容器**\n- 删除 不会使容器里的元素减少，留下元素前移，**没填上的维持原来的值**\n- 变序 改变容器中元素的顺序，**不适用于关联容器**\n- 排序 需要支持**随机访问迭代器**\n- 有序区间 已经**排好序+随机访问迭代器**\n- 数值\n\\### STL 中的大小相等判断\n1. 缺省的情况下，比较大小是用`<`进行的，**与\\>无关**\n2. 相等判断\n1. 在**未排序**的区间用`==`，例如find\n2. 在**排好序**的区间\n相等等价于**x\\<y与y\\<x同时成立**\n与`==`运算符无关\n\n### find\n\n``` cpp\n#include <algorithm>\n\nstd::find(begin, end, value);\n```\n\n参数：\n- `begin`：起始迭代器\n- `end`：结束迭代器\n- `value`：要查找的值\n返回值：\n- 找到 → 返回指向该元素的迭代器\n- 未找到 → 返回 `end`\n\n``` cpp\n#include <iostream>\n#include <vector>\n#include <algorithm>\n\nint main() {\n    std::vector<int> v = {1, 2, 3, 4, 5};\n\n    auto it = std::find(v.begin(), v.end(), 3);\n\n    if (it != v.end()) {\n        std::cout << \"找到元素: \" << *it << std::endl;\n    } else {\n        std::cout << \"未找到元素\" << std::endl;\n    }\n\n    return 0;\n}\n```"},
        {"STL库 — 算法", "### copy\n\n``` cpp\n#include <algorithm>\n\nstd::copy(begin, end, dest_begin);\n```\n\n参数说明：\n- `begin`：源区间起始迭代器\n- `end`：源区间结束迭代器\n- `dest_begin`：目标区间起始迭代器\n返回值：返回指向目标区间**最后一个被拷贝元素的下一个位置**的迭代器\n\n``` cpp\n#include <iostream>\n#include <vector>\n#include <algorithm>\n\nusing namespace std;\n\nint main() {\n    vector<int> v1 = {1, 2, 3, 4, 5};\n    vector<int> v2(5);   // 必须提前开空间！\n\n    copy(v1.begin(), v1.end(), v2.begin());\n\n    for (int x : v2)\n        cout << x << \" \";\n}\n```"},
        {"This指针 — > 指向成员函数所**作用的对象**", "> 每个成员函数都有一个this指针，你只是看不到它而已。\n\n``` cpp\n// 你写的代码\nclass A {\n    int x;\n    void foo(int v) { x = v; }\n};\n\n// 编译器实际生成的（伪代码）\nvoid A_foo(A* const this, int v) {\n    this->x = v;\n}\n```\n\nthis指针在大部分情况下可以省略，但在一些情况中发挥重要作用：\n1. 解决类的成员变量名与传入参数名的冲突\n\n``` cpp\nclass Person { private: int age; \npublic: // 参数名也是 age，如果不加 this，编译器会以为你在用参数给自己赋值（age = age） \nvoid setAge(int age) { \n    this->age = age; // this->age 是类的成员，右边的 age 是传进来的参数 \n    } \n};\n```\n\n2.  返回对象本身(链式调用)\n\n``` cpp\nclass Car {\npublic:\n    Car& setEngine() {\n        cout << \"安装引擎\";\n        return *this; // 返回对象本身\n    }\n    Car& setWheels() {\n        cout << \"安装轮子\";\n        return *this; \n    }\n};\n\nint main() {\n    Car myCar;\n    // 只有返回了 *this，才能一直点下去\n    myCar.setEngine().setWheels(); \n}\n```\n\n3.  把\"自己\"作为参数传给别的函数\n\n``` cpp\nclass Player;\n\nclass Game {\npublic:\n    void addPlayer(Player* p) { /* 把玩家加入游戏房间 */ }\n};\n\nclass Player {\npublic:\n    void joinGame(Game& game) {\n        // 玩家主动加入游戏。我要把“我自己”传给 game 对象，怎么传？只能用 this！\n        game.addPlayer(this); \n    }\n};\n```\n\n4.  防止自赋值\n\n``` cpp\nclass MyString {\n    char* data;\npublic:\n    MyString& operator=(const MyString& other) {\n        // 如果对象的地址 和 传进来的对象的地址 一样，说明是 obj = obj;\n        if (this == &other) {\n            return *this; // 直接返回，防止后续代码把自己的数据误删了\n        }\n        \n        // 否则执行正常的赋值逻辑...\n        return *this;\n    }\n};\n```\n\n> 关于this指针与静态成员函数\n> 静态成员函数中不能使用this指针（不具体作用于某个对象）"},
        {"const — 一、const 的本质", "`const` 是 C++ 中的**类型限定符（type qualifier）**，表示\"**只读/不可修改**\"。编译器会在编译期检查是否存在违反 `const` 约束的操作。\n\n``` cpp\nconst int x = 10;\nx = 20;  // ❌ 编译错误：不能修改 const 变量\n```"},
        {"const — 二、const 修饰变量", "### 2.1 const 修饰普通变量\n\n``` cpp\nconst int a = 10;   // 必须初始化\nint const b = 20;   // 与上面等价（const 和类型名可交换位置）\n\na = 30;  // ❌ 编译错误\n```\n\n**与宏定义 `#define` 的对比：**\n\n| 特性   | `#define PI 3.14`      | `const double PI = 3.14` |\n|--------|------------------------|--------------------------|\n| 时机   | 预处理阶段**文本替换** | 编译阶段类型检查         |\n| 类型   | 无类型                 | 有明确类型               |\n| 作用域 | 全局（无作用域）       | 遵循正常作用域规则       |\n| 调试   | 符号表中无名字         | 有名字，可调试           |\n| 推荐   | ❌                     | ✅                       |\n\n### 2.2 const 修饰数组\n\n``` cpp\nconst int arr[] = {1, 2, 3};\narr[0] = 10;  // ❌ 编译错误：元素不可修改\n```"},
        {"const — 二、const 修饰变量", "### 2.3 const 与编译期常量\n\n``` cpp\nconst int SIZE = 100;\nint arr[SIZE];        // ✅ C++ 中 const 整型可作为数组大小\n\n// constexpr（C++11）更明确表示编译期常量\nconstexpr int SIZE2 = 200;\nint arr2[SIZE2];      // ✅\n```\n\n------------------------------------------------------------------------"},
        {"const — 三、const 与指针", "### 3.1 四种组合\n\n``` cpp\nint x = 10, y = 20;\n\n// ① 指向常量的指针（底层 const）\nconst int* p1 = &x;\n*p1 = 30;    // ❌ 不能修改所指内容\np1 = &y;     // ✅ 可以改变指向\n\n// ② 常量指针（顶层 const）\nint* const p2 = &x;\n*p2 = 30;    // ✅ 可以修改所指内容\np2 = &y;     // ❌ 不能改变指向\n\n// ③ 指向常量的常量指针\nconst int* const p3 = &x;\n*p3 = 30;    // ❌ 不能修改所指内容\np3 = &y;     // ❌ 不能改变指向\n```\n\n### 3.2 const 指针的赋值兼容性\n\n``` cpp\nint x = 10;\nconst int cx = 20;\n\n// 非 const → const：✅ 安全（权限缩小）\nconst int* p1 = &x;     // ✅\n\n// const → 非 const：❌ 危险（权限放大）\nint* p2 = &cx;          // ❌ 编译错误\nint* p3 = p1;           // ❌ 编译错误\n\n// 需要强制转换（不推荐）\nint* p4 = const_cast<int*>(&cx);  // ⚠️ 可以编译，但修改 cx 是未定义行为\n```"},
        {"const — 四、const 与引用", "### 4.1 常量引用（const 引用）\n\n``` cpp\nint x = 10;\nconst int& ref = x;   // ref 是 x 的常量引用\n\nref = 20;   // ❌ 不能通过 ref 修改 x\nx = 20;     // ✅ 可以直接修改 x（ref 的值也变为 20）\n```\n\n> **注意**：不存在 `int& const ref`（引用本身天然不可重新绑定，加 const 无意义）。\n\n### 4.2 const 引用可以绑定到右值/临时对象\n\n``` cpp\nconst int& r1 = 42;            // ✅ 绑定字面量\nconst int& r2 = x + y;         // ✅ 绑定表达式结果\nconst string& r3 = \"hello\";    // ✅ 绑定临时 string 对象\n\nint& r4 = 42;                  // ❌ 非 const 引用不能绑定右值\n```\n\n**原理：** 编译器会创建一个临时对象，`const` 引用延长其生命周期。\n\n``` cpp\nconst int& r = 42;\n// 等价于：\n// int __temp = 42;\n// const int& r = __temp;  \n// __temp 的生命周期延长至 r 的作用域结束\n```\n\n### 4.3 const 引用的赋值兼容性\n\n``` cpp\nint x = 10;\nconst int cx = 20;\n\nconst int& r1 = x;    // ✅ 非const对象 → const引用（权限缩小）\nconst int& r2 = cx;   // ✅ const对象 → const引用\nint& r3 = cx;         // ❌ const对象 → 非const引用（权限放大）\n\n// 不同类型也可以（会产生临时对象）\ndouble d = 3.14;\nconst int& r4 = d;    // ✅ 绑定到由 d 转换而来的临时 int 对象\nint& r5 = d;          // ❌ 非const引用不能绑定临时对象\n```"},
        {"const — 五、const 与函数", "### 5.1 const 修饰函数参数\n\n#### （1）const 值传递\n\n``` cpp\nvoid func(const int x) {\n    x = 10;  // ❌ 函数内不能修改 x\n}\n\nint a = 5;\nfunc(a);  // a 本身不受影响（值传递是拷贝）\n```\n\n> 对调用方无影响，只约束函数内部。实际开发中较少使用。\n\n#### （2）const 引用传递\n\n``` cpp\nvoid print(const string& s) {\n    // s 不可修改，避免了拷贝开销\n    cout << s << endl;\n}\n\nconst string cs = \"hello\";\nstring s = \"world\";\n\nprint(cs);            // ✅ const 对象可以传入\nprint(s);             // ✅ 非 const 对象也可以传入\nprint(\"temporary\");   // ✅ 临时对象也可以传入\nprint(s + cs);        // ✅ 表达式结果（临时对象）也可以传入\n```\n\n**不加 const 的问题：**\n\n``` cpp\nvoid print(string& s) {     // 非 const 引用\n    cout << s << endl;\n}\n\nprint(cs);            // ❌ const 对象不能传入\nprint(\"temporary\");   // ❌ 临时对象不能传入\nprint(s + cs);        // ❌ 临时对象不能传入\n```\n\n#### （3）const 指针传递\n\n``` cpp\nvoid func(const int* p) {\n    *p = 10;  // ❌ 不能通过 p 修改所指内容\n    p = nullptr;  // ✅ 可以改变 p 本身（p 是值传递）\n}\n\nvoid func2(int* const p) {\n    *p = 10;  // ✅ 可以修改所指内容\n    p = nullptr;  // ❌ 不能改变 p 本身\n}\n```\n\n### 5.2 const 修饰函数返回值\n\n#### 返回 const 引用\n\n``` cpp\nclass MyClass {\n    string name;\npublic:\n    // ✅ 返回成员的只读访问\n    const string& getName() const {\n        return name;\n    }\n    \n    // ✅ 返回成员的可写访问\n    string& getName() {\n        return name;\n    }\n};\n\nMyClass obj;\ncout << obj.getName();       // 调用非 const 版本\nconst MyClass cobj;\ncout << cobj.getName();      // 调用 const 版本\ncobj.getName() = \"test\";     // ❌ 返回的是 const string&\n```\n\n#### 返回 const 指针\n\n``` cpp\nclass Array {\n    int* data;\npublic:\n    const int* getData() const {\n        return data;  // 调用方不能通过返回的指针修改数据\n    }\n};\n```"},
        {"const — 六、const 成员函数（重点）", "### 6.1 基本语法\n\n``` cpp\nclass MyClass {\n    int value;\npublic:\n    int getValue() const {    // const 成员函数\n        return value;\n    }\n    \n    void setValue(int v) {    // 非 const 成员函数\n        value = v;\n    }\n};\n```\n\n### 6.2 含义\n\n`const` 成员函数中，`this` 指针变为 `const MyClass* const this`：\n\n- 不能修改任何成员变量\n- 不能调用其他非 const 成员函数\n\n``` cpp\nclass MyClass {\n    int value;\n    int cache;\npublic:\n    int compute() const {\n        value = 10;         // ❌ 不能修改成员变量\n        cache = 20;         // ❌ 不能修改成员变量\n        setValue(10);       // ❌ 不能调用非 const 成员函数\n        return value;       // ✅ 读取成员变量没问题\n    }\n    \n    void setValue(int v) {\n        value = v;          // ✅ 非 const 函数可以修改\n    }\n};\n```\n\n### 6.3 const 对象只能调用 const 成员函数\n\n``` cpp\nMyClass obj;\nconst MyClass cobj;\n\nobj.getValue();     // ✅\nobj.setValue(10);    // ✅\n\ncobj.getValue();    // ✅ const 对象调用 const 成员函数\ncobj.setValue(10);  // ❌ const 对象不能调用非 const 成员函数\n```\n\n### 6.4 const 重载\n\n同一个函数可以有 const 和非 const 两个版本：\n\n``` cpp\nclass Array {\n    int data[10];\npublic:\n    // 非 const 版本：返回可修改的引用\n    int& operator[](int index) {\n        cout << \"non-const version\" << endl;\n        return data[index];\n    }\n    \n    // const 版本：返回只读引用\n    const int& operator[](int index) const {\n        cout << \"const version\" << endl;\n        return data[index];\n    }\n};\n\nArray arr;\nconst Array carr;\n\narr[0] = 5;         // 调用非 const 版本 ✅\nint x = carr[0];    // 调用 const 版本 ✅\ncarr[0] = 5;        // 调用 const 版本，返回 const int&，不能赋值 ❌\n```\n\n非`const`对象优先调用非`const`函数；\n`const`对象只能调用`const`函数\n\\### 6.5 mutable：突破 const 的限制\n\n`mutable` 成员变量可以在 `const` 成员函数中被修改：\n\n``` cpp\nclass MyClass {\n    int value;\n    mutable int accessCount;    // mutable 修饰\n    mutable bool cacheValid;\n    mutable int cachedResult;\npublic:\n    int getValue() const {\n        ++accessCount;          // ✅ mutable 变量可以在 const 函数中修改\n        \n        if (!cacheValid) {\n            cachedResult = /* 复杂计算 */;\n            cacheValid = true;  // ✅\n        }\n        return cachedResult;\n    }\n};\n```\n\n**典型用途：**\n- 访问计数器\n- 缓存/懒加载\n- 互斥锁（`mutable std::mutex mtx;`）\n\\## 七、const 与类\n\n### 7.1 const 成员变量\n\n``` cpp\nclass MyClass {\n    const int id;       // const 成员变量\n    const int maxSize;\npublic:\n    // ✅ 必须在初始化列表中初始化\n    MyClass(int i, int m) : id(i), maxSize(m) {\n        // id = i;      // ❌ 不能在函数体中赋值\n    }\n};\n```\n\n### 7.2 const 对象\n\n``` cpp\nconst MyClass obj(1, 100);\n// obj 的所有成员都视为 const\n// 只能调用 const 成员函数\n```\n\n### 7.3 const 与构造/析构函数"},
        {"const — 六、const 成员函数（重点）", "``` cpp\nclass MyClass {\npublic:\n    MyClass() {}        // 构造函数不能是 const（需要初始化成员）\n    ~MyClass() {}       // 析构函数不能是 const（需要清理资源）\n    // const MyClass() {}     // ❌ 语法错误\n};\n```\n\n### 7.4 static 与 const\n\n``` cpp\nclass MyClass {\n    static const int SIZE = 100;         // ✅ 类内初始化（整型）\n    static constexpr double PI = 3.14;   // ✅ C++11 constexpr\n    static const string NAME;            // 声明\n};\n\n// 类外定义（非整型的 static const 需要类外定义）\nconst string MyClass::NAME = \"hello\";\n```\n\n------------------------------------------------------------------------"},
        {"const — 八、const 在运算符重载中的应用", "### 8.1 各种运算符的 const 规范\n\n``` cpp\nclass MyClass {\npublic:\n    // 算术运算符：产生新值，不修改操作数\n    MyClass operator+(const MyClass& rhs) const;\n    MyClass operator-(const MyClass& rhs) const;\n    MyClass operator*(const MyClass& rhs) const;\n\n    // 复合赋值运算符：修改自身，返回自身引用\n    MyClass& operator+=(const MyClass& rhs);    // 不加 const！需要修改 *this\n    MyClass& operator-=(const MyClass& rhs);\n\n    // 赋值运算符：修改自身\n    MyClass& operator=(const MyClass& rhs);     // 不加 const！\n\n    // 比较运算符：不修改任何操作数\n    bool operator==(const MyClass& rhs) const;\n    bool operator<(const MyClass& rhs) const;\n\n    // 下标运算符：const 和非 const 两个版本\n    int& operator[](int index);\n    const int& operator[](int index) const;\n\n    // 前置++：修改自身\n    MyClass& operator++();           // 不加 const\n    // 后置++：返回修改前的副本\n    MyClass operator++(int);         // 不加 const（需要修改自身）\n\n    // 输出运算符（友元）\n    friend ostream& operator<<(ostream& os, const MyClass& obj);\n    //不修改 obj\n};\n```"},
        {"string 类 — 初始化", "不能用字符或数字初始化\n可以将字符赋值给string对象\n\n长度：.length()\n赋值：= assign\n连接：+ append\n比较：\n关系运算符\\\ncompare(大于返回1，等于返回0，小于返回-1)\n子串：substr()\n交换：swap()\n寻找：\nfind() rfind() 找不到返回string::npos\nfind_first_of() find_last_of() 其中任何一个字母，找不到返回string::npos\nfind_first_not_of() find_last_not_of() 其中不在任何一个字母，找不到返回string::npos\n删除：erase()\n替换：replace()\n插入：insert()\n转为C类型字符串：\nc_str() const char\\* 类型\ndata() char\\* 类型"},
        {"函数 — 内联函数", "``` cpp\ninline int Max(int a,int b){}\n//直接插入代码、不会产生调用函数的语句\n```"},
        {"函数 — 函数重载------同名不同参数", "``` cpp\nint maxv(double x,double y){}\nint maxv(int x,int y){}\nint maxv(int x,int y,int z){}\n//根据实参个数和类型判断调用哪个函数\n//有二义性会error\n```\n\n注：成员函数也可以重载"},
        {"函数 — 缺省参数", "``` cpp\nvoid func(int x,int y=0,int z=0){}\n//最右边的连续若干个参数\n```\n\n注：成员函数也可以带有缺省参数"},
        {"函数对象与函数指针 — 函数对象", "重载了`()`为成员函数的类------\\>函数类\n这个类的对象------\\>函数对象\n\n函数对象的优点：可以**携带状态**\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass Counter {\n    int count = 0;\npublic:\n    int operator()(int x) {\n        count++;\n        return x + count;\n    }\n};\n\nint main() {\n    Counter c;\n\n    cout << c(10) << endl;  // 11\n    cout << c(10) << endl;  // 12\n    cout << c(10) << endl;  // 13\n}\n```\n\nSTL中的应用\n\n``` cpp\n#include <algorithm>\n#include <vector>\n#include <iostream>\n\nclass Greater {\npublic:\n    bool operator()(int a, int b) {\n        return a > b;\n    }\n};\n\nint main() {\n    vector<int> v = {1,4,2,3};\n\n    sort(v.begin(), v.end(), Greater());\n\n    for (int x : v)\n        cout << x << \" \";\n}\n```"},
        {"函数对象与函数指针 — 函数指针", "一般形式：`类型名(*指针变量名)(参数类型1,参数类型2,...)`\n- 类型名：被指函数的**返回值**的类型\n- (参数类型1,参数类型2,...)分别指函数的**所有参数**的类型\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 普通函数\nint add(int a, int b) {\n    return a + b;\n}\n\nint main() {\n    // 定义函数指针\n    int (*p)(int, int);\n    // 让指针指向函数\n    p = add;\n    // 通过函数指针调用函数\n    cout << p(3, 5) << endl;\n    return 0;\n}\n```"},
        {"动态内存分配 — ``` cpp", "P=new T;//P是类型为T*的指针\ndelete P\nP=new T[N]//P是类型为T*的指针,N可以是表达式\ndelete [] P\n//new分配的空间需要用delete进行释放\n```\n\n> 生成的类若没有delete则不会自动调用析构函数\n```"},
        {"引用 — ``` cpp", "int n;\nint & r=n;//r的类型是int &\n```\n\n    注：\n        1. 一定要初始化为某个变量\n        2. 初始化后不会引用别的变量\n        3. 只能引用变量\n        4. 可以用对象赋值\n    引用的应用：\n        函数参数的传引用\n        引用作为函数的返回值\n```"},
        {"引用 — 常引用", "``` cpp\nint n;\nconst int & r=n;//r的类型是const int &\n//r=200 编译报错\n```\n\n注：\n        1. 不能通过常引用去修改其引用的内容\n        2. T & or T可以给const T &赋值，反之则不行"},
        {"引用 — 常量", "``` cpp\n//定义常量\nconst int max_val=23;\nconst string school_name=\"Peking University\";\n//定义常量指针\nint n,m;\nconst int * p=&n;\n*p=5;//会报错\nn=4;//Ok\np=&m;//OK,指向可以变化\n//不能把常量指针赋值给非常量指针\n```"},
        {"模板 — 函数模板", "``` cpp\n#include <iostream>\nusing namespace std;\n\n// 函数模板\ntemplate <typename T>\nT myMax(T a, T b) {\n    return (a > b) ? a : b;\n}\n\nint main() {\n    cout << myMax(3, 5) << endl;         // int 类型\n    cout << myMax(2.7, 1.8) << endl;     // double 类型\n    cout << myMax('a', 'z') << endl;     // char 类型\n\n    return 0;\n}\n```\n\n函数模板中可以有**不止一个**类型参数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\ntemplate <typename T1, typename T2>//类型参数表\nvoid show(T1 a, T2 b) {\n    cout << \"a = \" << a << \", b = \" << b << endl;\n}\n\nint main() {\n    show(10, 3.14);       // T1 = int, T2 = double\n    show(\"hello\", 25);    // T1 = const char*, T2 = int\n\n    return 0;\n}\n```\n\n### 函数模板的重载\n\n- 函数模板可以重载，只要它们的**形参表或类型参数表**不同即可\n  调用顺序：\n\n1.  先找**参数完全匹配**的**普通函数**\n2.  再找**参数完全匹配**的**模板函数**\n3.  实参经过**自动类型转换**后能够匹配的**普通函数**\n4.  报错\n\n- 不会调用自动类型转换的模板函数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n//==================== 1. 函数模板重载 ====================\n// 模板1：两个参数类型相同\ntemplate <typename T>\nvoid test(T a, T b) {\n    cout << \"模板1：test(T, T)\" << endl;\n}\n\n// 模板2：两个参数类型可以不同\ntemplate <typename T, typename U>\nvoid test(T a, U b) {\n    cout << \"模板2：test(T, U)\" << endl;\n}\n\n//==================== 2. 普通函数 + 模板函数同名 ====================\nvoid func(int a, int b) {\n    cout << \"普通函数：func(int, int)\" << endl;\n}\n\ntemplate <typename T>\nvoid func(T a, T b) {\n    cout << \"模板函数：func(T, T)\" << endl;\n}\n\n//==================== 3. 只有模板函数 ====================\ntemplate <typename T>\nvoid onlyTemp(T a, T b) {\n    cout << \"模板函数：onlyTemp(T, T)\" << endl;\n}\n\nint main() {\n    cout << \"===== 函数模板重载 =====\" << endl;\n    test(1, 2);       // 两个都是 int\n    test(1, 2.5);     // int 和 double\n\n    cout << \"\\n===== 调用顺序演示 =====\" << endl;\n\n    // 1. 先找参数完全匹配的普通函数\n    cout << \"1. func(10, 20) -> \";\n    func(10, 20);\n\n    // 2. 再找参数完全匹配的模板函数\n    cout << \"2. func('a', 'b') -> \";\n    func('a', 'b');\n\n    // 3. 普通函数可以靠自动类型转换匹配\n    //    模板 func(T, T) 这里无法把 T 同时推导成 int 和 char\n    cout << \"3. func(10, 'a') -> \";\n    func(10, 'a');\n\n    // 4. 只有模板函数时，如果需要靠自动类型转换来统一 T，则报错\n    // onlyTemp(10, 2.5);   // 编译错误：T 无法同时推导为 int 和 double\n\n    return 0;\n}\n```"},
        {"模板 — 类模板", "``` cpp\n#include <iostream>\nusing namespace std;\n\n// 定义类模板\ntemplate <typename T>\nclass Box {\nprivate:\n    T data;\n\npublic:\n    Box(T d) {\n        data = d;\n    }\n\n    void show() {\n        cout << \"data = \" << data << endl;\n    }\n};\n\nint main() {\n    Box<int> b1(100);\n    b1.show();\n\n    Box<double> b2(3.14);\n    b2.show();\n\n    Box<char> b3('A');\n    b3.show();\n\n    return 0;\n}\n```\n\n用类模板定义对象的写法：\n`类模板名<真实类型参数表> 对象名(构造函数实参表)`\n编译器由类模板生成类的过程叫做**类模板的实例化**，由类模板实例化得到的类，叫**模板类**\n\n- 类模板的<类型参数表>中可以出现**非类型参数**\n\n### 类模板与派生\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// T 是“类型参数”\n// N 是“非类型参数”（一个整型常量）\ntemplate <typename T, int N>\nclass StaticArray {\nprivate:\n    // 利用传入的非类型参数 N，直接在编译期确定数组大小\n    T arr[N]; \n\npublic:\n    // 获取数组大小\n    int getSize() const {\n        return N; // N 在类里面相当于一个常量 (const int)\n    }\n\n    // 设置元素\n    void set(int index, T value) {\n        if (index >= 0 && index < N) {\n            arr[index] = value;\n        } else {\n            cout << \"索引越界！\" << endl;\n        }\n    }\n\n    // 获取元素\n    T get(int index) {\n        if (index >= 0 && index < N) {\n            return arr[index];\n        }\n        return T(); // 越界返回默认构造值\n    }\n};\n\nint main() {\n    // 实例化时：T 被替换为 int，N 被替换为 5\n    StaticArray<int, 5> myIntArray;\n    cout << \"数组大小为: \" << myIntArray.getSize() << endl;\n\n    myIntArray.set(0, 100);\n    myIntArray.set(4, 500);\n    myIntArray.set(5, 999); // 故意越界测试\n\n    cout << \"arr[0] = \" << myIntArray.get(0) << endl;\n    cout << \"arr[4] = \" << myIntArray.get(4) << endl;\n\n    return 0;\n}\n```\n\n注意事项：\n1. 传入的必须是**编译期常量**\n2. 非类型参数在模板内部是**只读**的（常量）\n3. 不同的非类型参数值，会生成**完全不同**的类，不能互相赋值\n\n### 类模板与派生\n\n#### 类模板从类模板派生\n\n> 模板------\\>模板\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类模板\ntemplate <typename T>\nclass Base {\nprotected:\n    T value;\n\npublic:\n    Base(T v) : value(v) {}\n\n    void showBase() {\n        cout << \"Base value = \" << value << endl;\n    }\n};\n\n// 派生类模板\ntemplate <typename T>\nclass Derived : public Base<T> {//表示用T初始化Base类\nprivate:\n    T extraValue;\n\npublic:\n    Derived(T v1, T v2) : Base<T>(v1), extraValue(v2) {}\n\n    void showDerived() {\n        cout << \"Derived extraValue = \" << extraValue << endl;\n    }\n};\n\nint main() {\n    Derived<int> d1(10, 20);\n    d1.showBase();\n    d1.showDerived();\n\n    Derived<double> d2(3.14, 6.28);\n    d2.showBase();\n    d2.showDerived();\n\n    return 0;\n}\n```\n\n#### 类模板从模板类派生\n\n> 类------\\>模板\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类模板\ntemplate <typename T>\nclass Base {\nprotected:\n    T value;\n\npublic:\n    Base(T v) : value(v) {\n        cout << \"Base<T> constructor, value = \" << value << endl;\n    }\n\n    void showBase() {\n        cout << \"Base value = \" << value << endl;\n    }\n};\n\n// 类模板从模板类派生\n// 派生类是模板，基类是 Base<int>（模板类）\ntemplate <typename U>\nclass Derived : public Base<int> {\nprivate:\n    U data;\n\npublic:\n    Derived(int baseVal, U d) : Base<int>(baseVal), data(d) {\n        cout << \"Derived<U> constructor, data = \" << data << endl;\n    }\n\n    void showDerived() {\n        cout << \"Derived data = \" << data << endl;\n    }\n};\n\nint main() {\n    Derived<double> d1(100, 3.14);\n    d1.showBase();\n    d1.showDerived();\n\n    cout << \"---\" << endl;\n\n    Derived<string> d2(200, \"hello\");\n    d2.showBase();\n    d2.showDerived();\n\n    return 0;\n}\n```\n\n#### 类模板从普通类派生\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 普通基类\nclass Base {\nprotected:\n    int id;\n\npublic:\n    Base(int i) : id(i) {\n        cout << \"Base constructor, id = \" << id << endl;\n    }\n\n    void showBase() {\n        cout << \"Base id = \" << id << endl;\n    }\n};\n\n// 类模板从普通类派生\ntemplate <typename T>\nclass Derived : public Base {\nprivate:\n    T data;\n\npublic:\n    Derived(int i, T d) : Base(i), data(d) {\n        cout << \"Derived<T> constructor, data = \" << data << endl;\n    }\n\n    void showDerived() {\n        cout << \"Derived data = \" << data << endl;\n    }\n};\n\nint main() {\n    Derived<int> d1(100, 999);\n    d1.showBase();\n    d1.showDerived();\n\n    cout << \"---\" << endl;\n\n    Derived<string> d2(200, \"hello\");\n    d2.showBase();\n    d2.showDerived();\n\n    cout << \"---\" << endl;\n\n    Derived<double> d3(300, 3.14);\n    d3.showBase();\n    d3.showDerived();\n\n    return 0;\n}\n```\n\n#### 普通类从模板类派生\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 类模板（基类）\ntemplate <typename T>\nclass Container {\nprotected:\n    T data;\n\npublic:\n    Container(T d) : data(d) {\n        cout << \"Container<T> constructor, data = \" << data << endl;\n    }\n\n    void showData() {\n        cout << \"Data = \" << data << endl;\n    }\n};\n\n// 普通类从模板类派生\nclass IntContainer : public Container<int> {\nprivate:\n    string name;\n\npublic:\n    IntContainer(int d, string n) : Container<int>(d), name(n) {\n        cout << \"IntContainer constructor, name = \" << name << endl;\n    }\n\n    void showInfo() {\n        cout << \"Name: \" << name << endl;\n        showData();\n    }\n};\n\nint main() {\n    IntContainer obj(100, \"MyContainer\");\n    obj.showInfo();\n\n    return 0;\n}\n```\n\n### 类模板与友元\n\n#### 函数、类、类的成员函数作为类模板的友元\n\n``` cpp\n#include <iostream>\n#include <string>\nusing namespace std;\n\n// ========== 前置声明 ==========\ntemplate <typename T>\nclass Box;\n\n// 普通函数（将作为友元）\ntemplate <typename T>\nvoid printBox(const Box<T>& b);\n\n// 普通类（将作为友元类）\nclass BoxInspector {\npublic:\n    template <typename T>\n    void inspect(const Box<T>& b);\n};\n\n// 另一个类（它的成员函数将作为友元）\nclass BoxManager {\npublic:\n    template <typename T>\n    void manage(const Box<T>& b);\n};\n\n// ========== 类模板 Box ==========\ntemplate <typename T>\nclass Box {\nprivate:\n    T data;\n    int id;\n\npublic:\n    Box(T d, int i) : data(d), id(i) {}\n\n    // 1. 函数作为友元\n    friend void printBox<T>(const Box<T>& b);\n\n    // 2. 类作为友元\n    friend class BoxInspector;\n\n    // 3. 类的成员函数作为友元\n    friend void BoxManager::manage<T>(const Box<T>& b);\n};\n\n// ========== 友元函数的实现 ==========\n\n// 1. 普通函数的实现\ntemplate <typename T>\nvoid printBox(const Box<T>& b) {\n    cout << \"[Function Friend] Box ID: \" << b.id \n         << \", Data: \" << b.data << endl;\n}\n\n// 2. 友元类的成员函数实现\ntemplate <typename T>\nvoid BoxInspector::inspect(const Box<T>& b) {\n    cout << \"[Class Friend] Inspecting Box ID: \" << b.id \n         << \", Data: \" << b.data << endl;\n}\n\n// 3. 类的成员函数作为友元的实现\ntemplate <typename T>\nvoid BoxManager::manage(const Box<T>& b) {\n    cout << \"[Member Function Friend] Managing Box ID: \" << b.id \n         << \", Data: \" << b.data << endl;\n}\n\n// ========== 主函数 ==========\nint main() {\n    Box<int> b1(100, 1);\n    Box<string> b2(\"hello\", 2);\n    Box<double> b3(3.14, 3);\n\n    cout << \"=== 测试函数友元 ===\" << endl;\n    printBox(b1);\n    printBox(b2);\n    printBox(b3);\n\n    cout << \"\\n=== 测试类友元 ===\" << endl;\n    BoxInspector inspector;\n    inspector.inspect(b1);\n    inspector.inspect(b2);\n    inspector.inspect(b3);\n\n    cout << \"\\n=== 测试成员函数友元 ===\" << endl;\n    BoxManager manager;\n    manager.manage(b1);\n    manager.manage(b2);\n    manager.manage(b3);\n\n    return 0;\n}\n```\n\n#### 类模板与静态成员变量\n\n- 每个**不同的模板实例**都有**自己独立的静态成员**\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\ntemplate <typename T>\nclass Box {\nprivate:\n    T data;\n    static int count;  // 静态成员变量声明\n\npublic:\n    Box(T d) : data(d) {\n        count++;\n        cout << \"Box<T> created, count = \" << count << endl;\n    }\n\n    ~Box() {\n        count--;\n    }\n\n    static int getCount() {\n        return count;\n    }\n\n    void show() {\n        cout << \"Data = \" << data << \", Count = \" << count << endl;\n    }\n};\n\n// 静态成员变量定义（必须在类外定义）\ntemplate <typename T>\nint Box<T>::count = 0;\n\nint main() {\n    cout << \"=== 创建 Box<int> 对象 ===\" << endl;\n    Box<int> b1(10);\n    Box<int> b2(20);\n    Box<int> b3(30);\n    cout << \"Box<int> count = \" << Box<int>::getCount() << endl;\n\n    cout << \"\\n=== 创建 Box<double> 对象 ===\" << endl;\n    Box<double> d1(3.14);\n    Box<double> d2(6.28);\n    cout << \"Box<double> count = \" << Box<double>::getCount() << endl;\n\n    cout << \"\\n=== 再次查看计数 ===\" << endl;\n    cout << \"Box<int> count = \" << Box<int>::getCount() << endl;\n    cout << \"Box<double> count = \" << Box<double>::getCount() << endl;\n\n    return 0;\n}\n```"},
        {"类与对象 — 类", "### 类成员的可访问范围\n\nprivate（默认）：成员函数\n    public：任何地方\n    protected：可以被成员函数和子类的成员函数访问\n\n注：在类的成员函数内部，可访问：\n            1. 当前对象的全部属性、函数\n            2. 同类其它对象的全部属性、函数\n\n### 构造函数\n\n名字与类名相同、可以有参数、不能有返回值\n    作用是初始化对象\n    默认生成无参构造函数（若自己定义了则不生成）\n    对象生成时自动被调用\n    可以有多个（参数个数or类型不同）\n    最好是public的，private不能直接用于初始化\n\n``` cpp\nclass Rectangle { \nprivate: int width, height; \npublic: \n    Rectangle() : width(0), height(0) { cout << \"调用了无参构造函数\" << endl; } \n    Rectangle(int side) : width(side), height(side) { cout << \"调用了单参数构造函数\" << endl; } \n    Rectangle(int w, int h) : width(w), height(h) { cout << \"调用了双参数构造函数\" << endl; } \n    void display() { cout << \"宽: \" << width << \", 高: \" << height << endl; } \n};\n```\n\n#### 构造函数在数组中的使用\n\n``` cpp\nclass test{\n    public:\n        test(int n){}//(1)\n        test(int n,m){}//(2)\n        test(){}//(3)\n};\ntest array[3]={1,test(1,2)};//(1)(2)(3)\n```\n\n#### 复制构造函数\n\n> 参数一定要是引用！！\n>\n> 只有一个参数\n> 形如X::X(X &) 或X::X(const X &)(前者不能以常量对象作为参数)\n> 生成默认复制构造函数、完成复制功能"},
        {"类与对象 — 类", "> 复制构造函数起作用的三种情况\n> 1. 用一个类的对象**初始化**同类的另一个对象\n\n``` cpp\nComplex c1;\nComplex c2(c1);\nComplex c2=c1;//初始化，不是赋值\n```\n\n2.  调用了**参数是类A的对象**的函数\n\n``` cpp\nvoid Func(A a1){}\n```\n\n3.  **返回值**是类A的对象\n\n``` cpp\nA Func(){\n    A b(4);\n    return b;\n}\n```\n\n\\#对象间赋值并不调用复制构造函数\n\\#### 类型转换构造函数\n\\#只有一个参数、且不是复制构造函数的构造函数\n\n``` cpp\nclass A{\n    int v;\n    public:\n        A(){}\n        A(int i):v(i){}//(1)\n        explicit A(string i){v=stoi(i);}//(2)\n}\nint main(){\n    A a1;\n    A a2=3;//隐式调用(1)\n    a2=5;\n    A a3=A(3)//显式调用(1)\n    A a4=\"4\"//隐式调用(2)❌\n    A a5=A(\"98\")//显式调用(2)\n    a5=A(\"11\")\n}\n```\n\n> 1.  (1)(2)均为类型转换构造函数，其中(2)为显式类型转换构造函数，需要显式调用，不能自动转换。\n> 2.  类型转换构造函数在**赋值**中也会用到\n\n### 析构函数\n\n~类名\n    没有参数和返回值\n    一个类至多一个\n    缺省析构函数什么也不做(若自己定义了则不生成)\n\n``` cpp\nclass string{\n    private:\n        char * p;\n    public:\n        string(){\n            p=new char[10];\n        }\n        ~string(){\n            delete [] p;\n        }\n}\n```\n\n#### 析构函数的调用"},
        {"类与对象 — 类", "> 1.  对象数组生命周期结束后，对象数组的**每个元素**的析构函数都会被调用\n> 2.  delete运算导致析构函数调用（局部/全局变量在离开作用域后自动调用析构函数，但是**new生成的对象不会自动调用析构函数**）\n> 3.  析构函数在对象作为函数返回值返回后被调用\n>     \\#### 构造函数与析构函数的调用顺序\n>     \\##### C++ 构造与析构顺序速查表"},
        {"类与对象 — 类", "| **场景类型** | **构造顺序 (Construction)** | **析构顺序 (Destruction)** | **记忆口诀** |\n|----|----|----|----|\n| **局部对象** | 按代码定义的先后顺序 | 按定义的**相反**顺序 | 后进先出 (LIFO) |\n| **成员变量** | 按类中**声明**的顺序 | 按声明的**相反**顺序 | 先有砖头后有房 |\n| **继承关系** | 基类 $\\rightarrow$ 派生类 | 派生类 $\\rightarrow$ 基类 | 先打地基再盖楼 |\n| **静态对象** | 首次执行到定义处时 | 程序结束（main 退出）时 | 寿终正寝 |\n| **多重继承** | 按继承列表的先后顺序 | 按继承列表的**相反**顺序 | 从左到右构造 |\n\n### 静态成员\n\n> 本质上为全局成员"},
        {"类与对象 — 类", "| 比较维度 | 普通成员变量 (Instance Member) | 静态成员变量 (Static Member) |\n|:---|:---|:---|\n| **关键字** | 无需特殊关键字 | 需要 `static` 修饰 |\n| **归属** | 属于每个具体对象 | 属于整个类，由所有对象共享 |\n| **存储位置** | 随对象存储（通常在栈或堆上） | 全局/静态存储区 |\n| **内存份数** | 每个对象各有一份独立拷贝 | 整个类仅存一份，不随对象增减（**哪怕一个对象都不存在也存在**） |\n| **生命周期** | 随对象创建而生，随对象销毁而亡 | 程序启动时分配，程序结束时释放 |\n| **是否占对象大小** | ✅ 计入 `sizeof(对象)` | ❌ 不计入 `sizeof(对象)` |\n| **初始化方式** | 构造函数、初始化列表或类内赋初值 | 类外定义并初始化（`const static` 整型除外） |\n| **声明/定义位置** | 类内声明并分配空间 | 类内声明，类外定义（C++17 可用 `inline static`） |\n| **类外访问方式** | 必须通过 `对象.成员` 或 `指针->成员` | `类名::成员` (推荐) 或 `对象.成员` |\n| **this 指针** | ✅ 可通过 `this->` 访问 | ❌ 与 `this` 无关，不依赖具体对象 |\n| **静态函数访问权** | ❌ 静态成员函数不可直接访问 | ✅ 静态成员函数可以访问 |\n| **普通函数访问权** | ✅ 可以访问 | ✅ 可以访问 |\n| **不完整类型支持** | ❌ 成员类型不能是所属类本身 | ✅ 可以是所属类类型（常用于单例模式） |\n| **典型用途** | 描述单个对象的特有属性（如姓名） | 对象计数、共享配置、单例模式、类级常量 |\n| **继承行为** | 派生类对象拥有基类成员的拷贝 | 基类与所有派生类共享同一个静态变量 |\n| **访问控制** | 受 `public/protected/private` 限制 | 同样受 `public/protected/private` 限制 |"},
        {"类与对象 — 类", "``` cpp\n//代码示例\nclass Student {\npublic:\n    std::string name;          // 普通成员：每个学生各有一个名字\n    static int totalCount;     // 静态成员：全班共享一个计数器\n\n    Student(const std::string& n) : name(n) { ++totalCount; }\n    Student(const student & other):name(other.name){++totalCount;}\n    ~Student() { --totalCount; }\n};\n\n// 类外定义并初始化（必须）\nint Student::totalCount = 0;\n\nint main() {\n    Student a(\"Tom\"), b(\"Jerry\");\n    // a.name 和 b.name 各自独立\n    // Student::totalCount == 2，两个对象共享\n}\n```\n\n### 成员对象与封闭类\n\n#### 封闭类\n\n> 有成员对象的类叫做封闭类\n> 注：封闭类的成员函数**不能**访问成员对象的私有成员\n\n##### 封闭类的构造函数\n\n> 必须通过**初始化列表**完成对成员对象的初始化\n\n``` cpp\nclass Engine {\n    int horsepower;\npublic:\n    Engine(int hp) : horsepower(hp) {\n        cout << \"Engine构造 hp=\" << hp << endl;\n    }\n    ~Engine() { cout << \"Engine析构\" << endl; }\n};\n\nclass Tire {\n    int size;\npublic:\n    Tire(int s) : size(s) {\n        cout << \"Tire构造 size=\" << s << endl;\n    }\n    ~Tire() { cout << \"Tire析构\" << endl; }\n};\n\n// ★ Car 就是封闭类（包含了 Engine 和 Tire 对象）\nclass Car {\n    Engine engine;    // 对象成员1\n    Tire tire;        // 对象成员2\n    int price;\npublic:\n    // 必须通过初始化列表来初始化对象成员\n    Car(int hp, int s, int p) : engine(hp), tire(s), price(p) {\n        cout << \"Car构造\" << endl;\n    }\n    ~Car() { cout << \"Car析构\" << endl; }\n};\n```\n\n##### 封闭类构造函数与析构函数的执行顺序\n\n1.  **对象成员**的构造先于**封闭类自身**的构造函数体执行\n2.  多个对象成员之间按**声明顺序**构造（与**初始化列表**书写顺序**无关**！）\n3.  **析构顺序与构造顺序完全相反**\n    \\##### 封闭类的复制构造函数\n\n> 若封闭类的对象是用**默认复制构造函数**初始化的，那么包含的**成员对象**也会用**复制构造函数**初始化\n\n### 友元\n\n> 1.  友元可以分为**友元函数**和**友元类**两种\n> 2.  友元类之间的关系**不能传递、不能继承**\n> 3.  友元是**单向**的\n\n#### 友元函数\n\n> 一个类的友元函数可以访问该类的**私有成员**"},
        {"类与对象 — 类", "可以将一个类的成员函数（**包括构造、析构函数**）or全局函数说明为另一个类的友元\n即\n\\>友元函数不是这个类的成员函数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass Box;  // 前向声明\n\n// =====================\n// Printer 类（其成员函数将作为 Box 的友元）\n// =====================\nclass Printer {\npublic:\n    void print(const Box& b);  // 先声明，稍后定义\n};\n\n// =====================\n// Box 类\n// =====================\nclass Box {\nprivate:\n    double length;\n    double width;\n\npublic:\n    Box(double l, double w) : length(l), width(w) {}\n\n    // ✅ 全局函数 做友元\n    friend double getArea(const Box& b);\n\n    // ✅ 另一个类的成员函数 做友元\n    friend void Printer::print(const Box& b);\n};\n\n// ---------- 全局友元函数的定义 ----------\ndouble getArea(const Box& b) {\n    // 直接访问 Box 的私有成员\n    return b.length * b.width;\n}\n\n// ---------- 成员友元函数的定义（必须在 Box 定义之后）----------\nvoid Printer::print(const Box& b) {\n    // 直接访问 Box 的私有成员\n    cout << \"长: \" << b.length << \", 宽: \" << b.width << endl;\n}\n\n// =====================\n// 主函数\n// =====================\nint main() {\n    Box box(5.0, 3.0);\n\n    // 调用全局友元函数\n    cout << \"面积: \" << getArea(box) << endl;\n\n    // 调用成员友元函数\n    Printer p;\n    p.print(box);\n\n    return 0;\n}\n```\n\n#### 友元类\n\n> 若A是B的友元类，那么A的成员函数可以访问B的私有成员\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// =====================\n// Box 类\n// =====================\nclass Box {\nprivate:\n    double length;\n    double width;\n    double height;\n\npublic:\n    Box(double l, double w, double h) \n        : length(l), width(w), height(h) {}\n\n    // ✅ 声明 Inspector 为友元类\n    // Inspector 的所有成员函数都能访问 Box 的私有成员\n    friend class Inspector;\n};\n\n// =====================\n// Inspector 类（Box 的友元类）\n// =====================\nclass Inspector {\npublic:\n    // 计算体积\n    double getVolume(const Box& b) {\n        return b.length * b.width * b.height;  // ✅ 可访问私有成员\n    }\n\n    // 计算表面积\n    double getSurfaceArea(const Box& b) {\n        return 2 * (b.length * b.width       // ✅ 可访问私有成员\n                   + b.length * b.height \n                   + b.width  * b.height);\n    }\n\n    // 打印信息\n    void printInfo(const Box& b) {\n        cout << \"===== Box 信息 =====\" << endl;\n        cout << \"长: \" << b.length << endl;   // ✅ 可访问私有成员\n        cout << \"宽: \" << b.width  << endl;\n        cout << \"高: \" << b.height << endl;\n        cout << \"体积:   \" << getVolume(b)      << endl;\n        cout << \"表面积: \" << getSurfaceArea(b)  << endl;\n    }\n};\n\n// =====================\n// 主函数\n// =====================\nint main() {\n    Box box(5.0, 3.0, 2.0);\n\n    Inspector inspector;\n    inspector.printInfo(box);\n\n    return 0;\n}\n```\n\n### 常量成员函数\n\n> 1.  常量成员函数内部不能改变属性的值，也不能调用非常量成员函数\n>\n> - 若变量加上mutable关键字，则此变量在const函数中也能被修改\n>\n> 2.  在**定义和声明**常量成员函数时都应该使用const关键字（写在参数与函数体之间）\n\n``` cpp\nclass Article {\nprivate:\n    string text = \"这是一篇好文章\";\n    \n    // 加上 mutable，表示这个变量即使在 const 函数中也能被修改\n    mutable int readCount = 0; \n    int book_number=0;\n\npublic:\n    // 这是一个常量函数（只读）\n    void read() const {\n        cout << text << endl; // 正常读取文章\n        \n        readCount++; // ✅ 合法！因为 readCount 声明为了 mutable\n        //book_number++;不合法，编译会报错\n        cout << \"文章被阅读了 \" << readCount << \" 次\" << endl;\n    }\n};\n```\n\n> 常量成员函数的重载:\n> **同名函数**，仅通过有无 `const` 修饰来区分，构成重载。\n\n``` cpp\nclass A {\npublic:\n    void func();        // 非 const 版本\n    void func() const;  // const 版本  ← 两者构成重载！\n};\n```"},
        {"类与对象 — 类", "- 普通对象**优先**调用非const版本\n- const 对象**只能**调用const版本\n  \\>与是否重载无关，const对象只能调用const成员函数\n  \\## 对象\n  定义：类定义出来的变量\n  内存分配：成员变量大小之和（不包括成员函数）\n  运算：可以用=赋值，其他需经过运算符重载\n  \\### 使用类的成员变量和成员函数\n\n``` cpp\n//用法一：对象名.成员名\nCRectangle r1,r2;\nr1.w=5;\nr2.Init(5,4);\n//用法二：指针——>成员名\nCRectangle r1,r2;\nCRectangle * p1= & r1;\np1->w=5;\np1->Init(5,4);\n//用法一：引用名.成员名\nCRectangle r1;\nCRectangle & rr=r1;\nrr.w=5;\nrr.Init(5,4);\n```\n\n### const成员和引用成员的初始化\n\n> 在构造函数中必须使用初始化列表，不能在函数体中赋值\n\n``` cpp\nclass Test { \n    const int a; \n    int& b; \n    public: // 执行顺序：先执行冒号后的初始化列表，再执行 {} 里的内容 \n    Test(int val, int& ref) : a(val), b(ref) { \n        // 函数体可以为空，或者做其他非初始化操作 \n    } \n};\n```"},
        {"继承与派生 — 基类与派生类", "> 若B是A，则可由A为基类派生出B\n\n- 派生类是通过对基类进行修改和扩充得到的\n- 派生类定义后不依赖于基类，可以独立使用\n- 派生类拥有基类的所有成员函数和成员变量\n- 派生类可以扩充新的成员函数和成员变量\n\n``` cpp\nclass 派生类名：public 基类名{\n\n}；\n```\n\n### 派生类的内存空间\n\n派生类对象的体积=基类对象的体积+自己的成员变量的体积\n\n基类对象的存储位置位于派生类新增的成员变量之前"},
        {"继承与派生 — 继承与复合", "B是A，继承关系-\\>派生类\nB是A的特性，复合关系-\\>封闭类"},
        {"继承与派生 — 覆盖", "定义：派生类可以定义一个和基类成员同名的成员\n访问顺序：\n在派生类中访问同名成员时，缺省的情况是访问派生类中定义的成员，要访问基类同名成员需要使用`作用域符号::`\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类\nclass Base {\npublic:\n    void show() {\n        cout << \"这是基类中的 show()\" << endl;\n    }\n};\n\n// 派生类\nclass Derived : public Base {\npublic:\n    void show() {\n        cout << \"这是派生类中的 show()\" << endl;\n    }\n};\n\nint main() {\n    Derived d;\n\n    d.show();        // 默认访问派生类中的 show()\n    d.Base::show();  // 访问基类中的 show()\n\n    return 0;\n}\n```\n\n> 只要同名就会覆盖，即使参数表不同\n\n当派生类中定义了一个与基类同名但参数表不同的成员函数时，基类中所有同名函数都会被隐藏，而不是与派生类函数共同形成重载。\n    此时，若要访问基类中的同名函数，必须使用作用域运算符 `::` 显式指出。\n\n### 保护成员 protected\n\n可被下列函数访问：\n- 基类的成员函数\n- 基类的友元函数\n- 派生类的成员函数\n\n### 派生类的构造函数\n\n先构造基类，通过调用基类的构造函数（在初始化列表中）\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类\nclass Person {\npublic:\n    Person(string name) {\n        cout << \"基类构造函数，姓名：\" << name << endl;\n    }\n};\n\n// 派生类\nclass Student : public Person {\npublic:\n    Student(string name, int age) : Person(name) {\n        cout << \"派生类构造函数，年龄：\" << age << endl;\n    }\n};\n\nint main() {\n    Student s(\"张三\", 20);\n    return 0;\n}\n```\n\n### 封闭派生类对象的构造函数\n\n``` cpp\n#include <iostream>\n#include <string>\nusing namespace std;\n\n// 普通类：用作成员对象\nclass Phone {\nprivate:\n    string number;\n\npublic:\n    Phone(string num) : number(num) {\n        cout << \"Phone 构造函数被调用\" << endl;\n    }\n\n    void showPhone() {\n        cout << \"电话: \" << number << endl;\n    }\n};\n\n// 基类\nclass Person {\nprivate:\n    string name;\n    int age;\n\npublic:\n    Person(string n, int a) : name(n), age(a) {\n        cout << \"Person 构造函数被调用\" << endl;\n    }\n\n    void showPerson() {\n        cout << \"姓名: \" << name << \", 年龄: \" << age << endl;\n    }\n};\n\n// 封闭派生类：继承 Person，包含 Phone 成员对象\nclass Student : public Person {\nprivate:\n    int studentId;\n    Phone phone;  // 成员对象\n\npublic:\n    // 封闭派生类构造函数\n    Student(string n, int a, int id, string phoneNum)\n        : Person(n, a),        // 1. 初始化基类\n          phone(phoneNum),     // 2. 初始化成员对象\n          studentId(id)        // 3. 初始化自身成员\n    {\n        cout << \"Student 构造函数被调用\" << endl;\n    }\n\n    void showStudent() {\n        showPerson();\n        phone.showPhone();\n        cout << \"学号: \" << studentId << endl;\n    }\n};\n\nint main() {\n    cout << \"===== 创建对象 =====\" << endl;\n    Student s(\"张三\", 20, 10001, \"13800001111\");\n\n    cout << \"\\n===== 显示信息 =====\" << endl;\n    s.showStudent();\n\n    return 0;\n}\n```\n\n构造顺序为：\n1. 先构造基类部分\n2. 再构造成员对象\n3. 最后构造派生类自身\n\n- 析构函数的执行顺序与构造函数相反\n  \\## 继承方式\n  \\### public 继承"},
        {"继承与派生 — 覆盖", "赋值兼容规则（针对public继承）\n1. 派生类的对象可以赋值给**基类对象**\n2. 派生类对象可以初始化**基类引用**\n3. 派生类对象的地址可以赋值给**基类指针**\n\n基类与派生类的指针\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类\nclass Animal {\npublic:\n    string name = \"动物\";\n    void eat() {\n        cout << \"Animal::eat()\" << endl;\n    }\n};\n\n// 派生类\nclass Dog : public Animal {\npublic:\n    string breed = \"金毛\";\n    void eat() {  // 覆盖基类函数\n        cout << \"Dog::eat()\" << endl;\n    }\n\n    void bark() {  // 派生类新增函数\n        cout << \"Dog::bark() 汪汪汪！\" << endl;\n    }\n};\n\nint main() {\n    Dog dog;\n\n    // ===== 派生类指针指向派生类对象 =====\n    Dog* pDog = &dog;\n    pDog->eat();    // Dog::eat()\n    pDog->bark();   // Dog::bark()\n\n    // ===== 基类指针指向派生类对象 =====\n    Animal* pAnimal = &dog;  // ✅ 允许\n    pAnimal->eat();          // Animal::eat()（调用基类版本）\n    // pAnimal->bark();       // ❌ 错误！基类指针看不到派生类新增成员\n\n    // ===== 派生类指针指向基类对象 =====\n    Animal animal;\n    // Dog* pDog2 = &animal;  // ❌ 错误！不允许\n\n    return 0;\n}\n```\n\n| 操作        | 结果                              |\n|-------------|-----------------------------------|\n| `p->name`   | ✅ 可访问（基类成员）             |\n| `p->eat()`  | ✅ 可调用，但调用的是**基类版本** |\n| `p->breed`  | ❌ 不可访问（派生类新增成员）     |\n| `p->bark()` | ❌ 不可调用（派生类新增函数）     |"},
        {"继承与派生 — 覆盖", "> 基类指针只能\"看到\"基类中定义的成员，**看不到派生类新增的成员**。\n> \\### protected 继承\n> 基类的**public成员和protected成员**成为派生类的**protected成员**\n\n### private继承\n\n基类的**public成员**成为派生类的**private成员**，基类的**protected成员**成为派生类的**不可访问成员**"},
        {"继承与派生 — 直接基类与间接基类", "在继承关系中，一个类继承时所**直接写在类名后面**的基类，称为**直接基类**；\\\n如果某个基类不是当前类直接继承得到的，而是通过上一层继承关系间接获得的，则称为**间接基类**。\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass A {\npublic:\n    void showA() {\n        cout << \"A 是基类\" << endl;\n    }\n};\n\nclass B : public A {\npublic:\n    void showB() {\n        cout << \"B 直接继承 A\" << endl;\n    }\n};\n\nclass C : public B {\npublic:\n    void showC() {\n        cout << \"C 直接继承 B\" << endl;\n    }\n};\n\nint main() {\n    C c;\n\n    c.showA();  // 来自 A\n    c.showB();  // 来自 B\n    c.showC();  // 自己的成员\n\n    return 0;\n}\n```\n\n成员包括：\n1. 派生类自己定义的成员\n2. 直接基类中的所有成员\n3. 所有间接基类的所有的成员"},
        {"虚函数与多态 — 虚函数", "在类的定义中，前面有`virtual`关键字的成员函数（virtual只需要在声明时添加）\n\\> 在编译时不确定调用哪一个，在运行时才确定\n\n派生类中与基类中虚函数同名同参数表的函数，不加`virtual`也自动成为虚函数\n\n### 构造函数与析构函数中调用虚函数------不是多态\n\n1.  在基类构造函数中**调用**虚函数，调用的是**基类自己的虚函数**，不会调用派生类重写的版本。\n2.  在基类析构函数中**调用**虚函数，调用的也仍然是**基类自己的虚函数**，不会调用派生类重写的版本。\n3.  析构函数**自身**可以是虚函数\n    \\## 多态\n    \\>在**指针**和**引用**中起效，对**传值**的函数调用**不起效**\n    \\### 虚函数与指针\n    通过基类指针调用基类与派生类的**同名虚函数**时：\n4.  指针指向**基类**，调用**基类**的虚函数\n5.  指针指向**派生类**，调用**派生类**的虚函数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类\nclass Animal {\npublic:\n    virtual void speak() {  // 虚函数\n        cout << \"Animal::speak()\" << endl;\n    }\n};\n\n// 派生类\nclass Dog : public Animal {\npublic:\n    void speak() {  // 重写虚函数\n        cout << \"Dog::speak() 汪汪汪！\" << endl;\n    }\n};\n\n// 派生类\nclass Cat : public Animal {\npublic:\n    void speak() {  // 重写虚函数\n        cout << \"Cat::speak() 喵喵喵！\" << endl;\n    }\n};\n\nint main() {\n    Animal animal;\n    Dog dog;\n    Cat cat;\n\n    Animal* p;  // 基类指针\n\n    // 1. 指向基类对象，调用基类的虚函数\n    p = &animal;\n    p->speak();  // Animal::speak()\n\n    // 2. 指向派生类对象，调用派生类的虚函数\n    p = &dog;\n    p->speak();  // Dog::speak()\n\n    p = &cat;\n    p->speak();  // Cat::speak()\n\n    return 0;\n}\n```\n\n### 虚函数与引用"},
        {"虚函数与多态 — 虚函数", "通过**基类引用**调用基类与派生类的**同名虚函数**时：\n1. 引用**基类**对象，调用**基类**的虚函数\n2. 引用**派生类**对象，调用**派生类**的虚函数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 基类\nclass Animal {\npublic:\n    virtual void speak() {  // 虚函数\n        cout << \"Animal::speak()\" << endl;\n    }\n};\n\n// 派生类\nclass Dog : public Animal {\npublic:\n    void speak() {  // 重写虚函数\n        cout << \"Dog::speak() 汪汪汪！\" << endl;\n    }\n};\n\n// 派生类\nclass Cat : public Animal {\npublic:\n    void speak() {  // 重写虚函数\n        cout << \"Cat::speak() 喵喵喵！\" << endl;\n    }\n};\n\n// 使用基类引用作为参数\nvoid makeSpeak(Animal& ref) {\n    ref.speak();  // 根据实际引用的对象调用相应的虚函数\n}\n\nint main() {\n    Animal animal;\n    Dog dog;\n    Cat cat;\n\n    // 1. 引用基类对象，调用基类的虚函数\n    Animal& ref1 = animal;\n    ref1.speak();  // Animal::speak()\n\n    // 2. 引用派生类对象，调用派生类的虚函数\n    Animal& ref2 = dog;\n    ref2.speak();  // Dog::speak()\n\n    Animal& ref3 = cat;\n    ref3.speak();  // Cat::speak()\n\n    // 通过函数参数传递引用\n    cout << \"\\n===== 通过函数调用 =====\" << endl;\n    makeSpeak(animal);  // Animal::speak()\n    makeSpeak(dog);     // Dog::speak()\n    makeSpeak(cat);     // Cat::speak()\n\n    return 0;\n}\n```\n\n### 动态连编\n\n虚函数表：每一个有虚函数的类（or 有虚函数的类的派生类）都有一个**虚函数表**，该类的任何对象中都放着虚函数表的指针。虚函数表中列出了该类的虚函数地址。\n\n有虚函数的类的size会增加4个字节，存的就是虚函数表的地址\n\n### 虚析构函数\n\n问题：通过基类的指针删除派生类对象时，通常只调用基类的析构函数\n解决方法：把**基类**的析构函数声明为**virtual**\n\n一般来说，一个类如果定义了虚函数or打算作为基类使用，则应该将析构函数定义为虚函数\n\n> 虚函数不允许作为构造函数\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// ========== 基类 ==========\nclass Animal {\npublic:\n    Animal() {\n        cout << \"Animal 构造函数\" << endl;\n    }\n\n    // ✅ 虚析构函数\n    virtual ~Animal() {\n        cout << \"Animal 析构函数\" << endl;\n    }\n};\n\n// ========== 派生类 ==========\nclass Dog : public Animal {\nprivate:\n    int* data;  // 模拟动态资源\n\npublic:\n    Dog() {\n        data = new int[100];\n        cout << \"Dog 构造函数（分配了内存）\" << endl;\n    }\n\n    ~Dog() override {\n        delete[] data;\n        cout << \"Dog 析构函数（释放了内存）\" << endl;\n    }\n};\n\n// ========== 主函数 ==========\nint main() {\n    cout << \"===== 通过基类指针删除派生类对象 =====\" << endl;\n    Animal* ptr = new Dog();   // 基类指针指向派生类对象\n    delete ptr;                // 触发多态析构\n\n    return 0;\n}\n```\n\n### 纯虚函数与抽象类\n\n定义：\n纯虚函数：**没有函数体**的虚函数\n\n``` cpp\nvirtual void show() = 0;\n```\n\n= 0 表示这个函数没有具体实现，要求派生类必须重写。\n\n抽象类：包含**纯虚函数**的类"},
        {"虚函数与多态 — 虚函数", "1.  抽象类只能作为基类来派生新类，**不能创建独立的抽象类的对象**\n2.  抽象类的指针和引用可以指向抽象类**派生出来的类的对象**\n3.  在抽象类的**成员函数**可以调用纯虚函数，但是**构造函数**和**析构函数**内部不能调用纯虚函数\n4.  如果一个类从抽象类派生而来，那么**当且仅当**它实现了基类里**所有纯虚函数**，它才能成为非抽象类\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\n// 抽象类\nclass Animal {\npublic:\n    virtual void speak() = 0;   // 纯虚函数\n};\n\nclass Dog : public Animal {\npublic:\n    void speak() override {\n        cout << \"狗在叫：汪汪！\" << endl;\n    }\n};\n\nclass Cat : public Animal {\npublic:\n    void speak() override {\n        cout << \"猫在叫：喵喵！\" << endl;\n    }\n};\n\nint main() {\n    // Animal a;   // 错误：抽象类不能实例化\n\n    Animal* p1 = new Dog();\n    Animal* p2 = new Cat();\n\n    p1->speak();\n    p2->speak();\n\n    delete p1;\n    delete p2;\n\n    return 0;\n}\n```"},
        {"运算符重载 — 定义", "> 对已有的运算符赋予多重的含义，拓展运算符的适用范围，使之能够作用于对象"},
        {"运算符重载 — 形式", "- 实质是函数重载\n- 可重载为普通函数or成员函数\n- 含运算符的表达式------\\>对运算符函数的调用\n- 运算符的操作数------\\>运算符函数的参数\n- 可多次重载，根据类型决定\n\n``` cpp\nclass Complex {\nprivate:\n    double real;\n    double imag;\n\npublic:\n    // 构造函数\n    Complex(double r = 0, double i = 0) : real(r), imag(i) {}\n\n    // 重载 + 运算符\n    Complex operator+(const Complex& other) const {\n        return Complex(real + other.real, imag + other.imag);\n    }\n\n    // 重载 == 运算符\n    bool operator==(const Complex& other) const {\n        return (real == other.real && imag == other.imag);\n    }\n\n    // 友元函数：重载 << 运算符，用于输出\n    friend ostream& operator<<(ostream& out, const Complex& c);\n};\n\n// 重载 << 运算符\nostream& operator<<(ostream& out, const Complex& c) {\n    out << c.real;\n    if (c.imag >= 0)\n        out << \"+\" << c.imag << \"i\";\n    else\n        out << c.imag << \"i\";\n    return out;\n}\n\nint main() {\n    Complex c1(3, 4);\n    Complex c2(1, 2);\n\n    Complex c3 = c1 + c2;\n\n    cout << \"c1 = \" << c1 << endl;\n    cout << \"c2 = \" << c2 << endl;\n    cout << \"c1 + c2 = \" << c3 << endl;\n\n    if (c1 == c2)\n        cout << \"c1 和 c2 相等\" << endl;\n    else\n        cout << \"c1 和 c2 不相等\" << endl;\n\n    return 0;\n}\n```\n\n### 不能重载的运算符\n\n- `.` 成员访问运算符\n- `.*` 成员指针访问运算符\n- `::` 作用域解析运算符\n- `?:` 三目运算符\n- `sizeof`\n\n### 只能重载为成员函数的运算符\n\n以下 **4个运算符** 在C++中只能重载为类的成员函数，不能重载为全局（友元）函数：\n\n| 运算符 | 名称           |\n|--------|----------------|\n| `=`    | 赋值运算符     |\n| `[]`   | 下标运算符     |\n| `()`   | 函数调用运算符 |\n| `->`   | 成员访问运算符 |\n\n### 赋值运算符`=`的重载"},
        {"运算符重载 — 形式", "> 1.  只能重载为成员函数\n> 2.  注意深拷贝与浅拷贝\n> 3.  返回值类型最好为`&`（保留连等的特性）\n\n### ++运算符的重载\n\n在 C++ 里，前置和后置 `++` 的重载是靠**函数参数列表**区分的：\n\n``` cpp\n// 前置 ++x\nCHugeInt& operator++();\n\n// 后置 x++\nCHugeInt operator++(int);\n```\n\n关键点：\n\n1.  前置：`operator++()`\n\n- 没有参数\n- 通常返回引用 `T&`（返回加完后的自身）\n\n2.  后置：`operator++(int)`\n\n- 多出来的 `int` 是\"占位参数\"，不使用，只为和前置区分\n- 通常返回值 `T`（返回加之前的旧值副本）\n\n### Rule of Three\n\n### 类型转换运算符的重载\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass Number {\nprivate:\n    double value;\n\npublic:\n    Number(double v) : value(v) {}\n\n    // 类型转换运算符重载\n    operator int() {\n        return (int)value;\n    }\n};\n\nint main() {\n    Number n(3.14);\n\n    int x = n;   // 自动调用 operator int()\n    cout << \"x = \" << x << endl;\n\n    return 0;\n}\n```\n\n注意事项：\n被重载时不能写返回值类型\n\n### 自增自减运算符的重载\n\n``` cpp\n#include <iostream>\nusing namespace std;\n\nclass Number {\nprivate:\n    int value;\n\npublic:\n    Number(int v) : value(v) {}\n\n    // 前置++\n    Number& operator++() {\n        ++value;\n        return *this;\n    }\n\n    // 后置++\n    Number operator++(int) {\n        Number temp = *this;\n        value++;\n        return temp;\n    }\n\n    void show() {\n        cout << \"value = \" << value << endl;\n    }\n};\n\nint main() {\n    Number n(5);\n\n    ++n;      // 前置++\n    n.show(); // 6\n\n    n++;      // 后置++\n    n.show(); // 7\n\n    return 0;\n}\n```\n\n- 前置函数作为**一元**运算符重载，后置函数作为**二元**运算符重载，多写一个没用的`int`参数\n- 前置函数多返回**引用**，后置函数多返回**值**"},
    };
    return s_entries;
}

KnowledgeEntry KnowledgeBank::drawRandom() {
    const auto& e = entries();
    if (e.isEmpty()) return {};
    int idx = QRandomGenerator::global()->bounded(e.size());
    return e[idx];
}
